                    if parsed and parsed.get("type") in ("transfer", "transferChecked"):
                        info = parsed.get("info", {})
                        source = info.get("source") or info.get("owner") or info.get("authority")
                        mint = info.get("mint")
                        amount = info.get("tokenAmount", {}).get("amount") or info.get("amount")
                        if source and mint and amount is not None:
                            transfers.append({
                                "account": source,
                                "mint": mint,
                                "amount": str(amount),
                            })
                except Exception:
                    continue
            return transfers
        transfers = []
        message = tx.get("transaction", {}).get("message", {})
        transfers += parse_transfers(message.get("instructions", []))
        for inner in (meta.get("innerInstructions") or []):
            transfers += parse_transfers(inner.get("instructions", []))
        out = {
            "signature": signature,
            "slot": slot,
            "block_time": block_time,
            "success": success,
            "fee": fee,
            "token_transfers": transfers,
        }
        return jsonify(out)
    except RPCException as e:
        return error_response(e, status=404)
    except Exception as e:
        return error_response(e)

@app.route("/account/<address>", methods=["GET"])
def get_account(address: str):
    try:
        resp = client.get_account_info(address, encoding="base64")
        if resp.get("error"):
            msg = resp.get("error", {}).get("message") if isinstance(resp.get("error"), dict) else resp.get("error")
            return error_response(msg or "Account not found", status=404)
        acc = (resp.get("result") or {}).get("value")
        if acc is None:
            return error_response("Account not found", status=404)
        out = {
            "address": address,
            "executable": acc.get("executable"),
            "lamports": acc.get("lamports"),
            "owner": acc.get("owner"),
            "rent_epoch": acc.get("rentEpoch"),
        }
        return jsonify(out)
    except RPCException as e:
        return error_response(e, status=404)
    except Exception as e:
        return error_response(e)

@app.route("/program/<program_id>/accounts", methods=["GET"])
def get_program_accounts(program_id: str):
    try:
        try:
            limit = int(request.args.get("limit", 10))
        except Exception:
            limit = 10
        try:
            offset = int(request.args.get("offset", 0))
        except Exception:
            offset = 0
        if limit < 0:
            limit = 10
        if offset < 0:
            offset = 0
        resp = client.get_program_accounts(program_id, encoding="base64")
        if resp.get("error"):
            msg = resp.get("error", {}).get("message") if isinstance(resp.get("error"), dict) else resp.get("error")
            return error_response(msg or "Program accounts not found", status=404)
        accounts = resp.get("result") or []
        total = len(accounts)
        slice_accounts = accounts[offset:offset+limit] if limit != 0 else []
        fmt_accounts = []
        for a in slice_accounts:
            acc = a.get("account", {})
            fmt_accounts.append({
                "pubkey": a.get("pubkey"),
                "account": {
                    "executable": acc.get("executable"),
                    "lamports": acc.get("lamports"),
                    "owner": acc.get("owner"),
                    "rent_epoch": acc.get("rentEpoch"),
                }
            })
        return jsonify({
            "program_id": program_id,
            "total_accounts": total,
            "limit": limit,
            "offset": offset,
            "accounts": fmt_accounts,
        })
    except RPCException as e:
        return error_response(e, status=404)
    except Exception as e:
        return error_response(e)

