}
RPC_URL = ENDPOINTS.get(NETWORK, ENDPOINTS["mainnet-beta"])
client = Client(RPC_URL)

app = Flask(__name__)

def error_response(message, status=500):
    resp = jsonify({"error": str(message)})
    resp.status_code = status
    return resp

@app.route("/status", methods=["GET"])
def status():
    online = False
    current_slot = None
    node_count = None
    version = None
    try:
        health = client.get_health()
        online = health.get("result") == "ok"
    except Exception:
        online = False
    try:
        slot_resp = client.get_slot()
        current_slot = slot_resp.get("result")
    except Exception:
        current_slot = None
    try:
        nodes_resp = client.get_cluster_nodes()
        nodes = nodes_resp.get("result") or []
        node_count = len(nodes)
    except Exception:
        node_count = None
    try:
        version_resp = client.get_version()
        version = version_resp.get("result", {}).get("solana-core")
    except Exception:
        version = None
    return jsonify({
        "status": "online" if online else "offline",
        "network": NETWORK,
        "current_slot": current_slot,
        "node_count": node_count,
        "version": version,
    })

@app.route("/block/<int:slot>", methods=["GET"])
def get_block(slot: int):
    try:
        resp = client.get_block(slot, encoding="json", max_supported_transaction_version=0)
        if resp.get("error") or resp.get("result") is None:
            msg = resp.get("error", {}).get("message") if isinstance(resp.get("error"), dict) else resp.get("error")
            return error_response(msg or "Block not found", status=404)
        block = resp["result"]
        out = {
            "blockhash": block.get("blockhash"),
            "parent_slot": block.get("parentSlot"),
            "previous_blockhash": block.get("previousBlockhash"),
            "block_height": block.get("blockHeight"),
            "block_time": block.get("blockTime"),
        }
        if out["blockhash"] is None:
            return error_response("Block not found", status=404)
        return jsonify(out)
    except RPCException as e:
        return error_response(e, status=404)
    except Exception as e:
        return error_response(e)

@app.route("/transaction/<signature>", methods=["GET"])
def get_transaction(signature: str):
    try:
        resp = client.get_transaction(signature, encoding="jsonParsed", max_supported_transaction_version=0)
        if resp.get("error") or resp.get("result") is None:
            msg = resp.get("error", {}).get("message") if isinstance(resp.get("error"), dict) else resp.get("error")
            return error_response(msg or "Transaction not found", status=404)
        tx = resp["result"]
        meta = tx.get("meta") or {}
        success = meta.get("err") is None
        fee = meta.get("fee")
        slot = tx.get("slot")
        block_time = tx.get("blockTime")
        def parse_transfers(instructions):
            transfers = []
            for ix in instructions:
                try:
                    parsed = ix.get("parsed")
                    if parsed and parsed.get("type") in ("transfer", "transferChecked"):
                        info = parsed.get("info", {})
                        source = info.get("source") or info.get("owner") or info.get("authority")
                        mint = info.get("mint")
                        amount = info.get("tokenAmount", {}).get("amount") or info.get("amount")
                        if source and mint and amount is not None:
                            transfers.append({
                                "account": source,
                                "mint": mint,
                                "amount": str(amount),
                            })
                except Exception:
                    continue
            return transfers
        transfers = []
        message = tx.get("transaction", {}).get("message", {})
        transfers += parse_transfers(message.get("instructions", []))
        for inner in (meta.get("innerInstructions") or []):
            transfers += parse_transfers(inner.get("instructions", []))
        out = {
            "signature": signature,
            "slot": slot,
            "block_time": block_time,
            "success": success,
            "fee": fee,
            "token_transfers": transfers,
        }
        return jsonify(out)
    except RPCException as e:
        return error_response(e, status=404)
    except Exception as e:
        return error_response(e)

@app.route("/account/<address>", methods=["GET"])
def get_account(address: str):
    try:
        resp = client.get_account_info(address, encoding="base64")
        if resp.get("error"):
            msg = resp.get("error", {}).get("message") if isinstance(resp.get("error"), dict) else resp.get("error")
            return error_response(msg or "Account not found", status=404)
        acc = (resp.get("result") or {}).get("value")
        if acc is None:
            return error_response("Account not found", status=404)
        out = {
            "address": address,
            "executable": acc.get("executable"),
            "lamports": acc.get("lamports"),
            "owner": acc.get("owner"),
            "rent_epoch": acc.get("rentEpoch"),
        }
        return jsonify(out)
    except RPCException as e:
        return error_response(e, status=404)
    except Exception as e:
        return error_response(e)

@app.route("/program/<program_id>/accounts", methods=["GET"])
def get_program_accounts(program_id: str):
    try:
        try:
            limit = int(request.args.get("limit", 10))
        except Exception:
            limit = 10
        try:
            offset = int(request.args.get("offset", 0))
        except Exception:
            offset = 0
        if limit < 0:
            limit = 10
        if offset < 0:
            offset = 0
        resp = client.get_program_accounts(program_id, encoding="base64")
        if resp.get("error"):
            msg = resp.get("error", {}).get("message") if isinstance(resp.get("error"), dict) else resp.get("error")
            return error_response(msg or "Program accounts not found", status=404)
        accounts = resp.get("result") or []
        total = len(accounts)
        slice_accounts = accounts[offset:offset+limit] if limit != 0 else []
        fmt_accounts = []
        for a in slice_accounts:
            acc = a.get("account", {})
            fmt_accounts.append({
                "pubkey": a.get("pubkey"),
                "account": {
                    "executable": acc.get("executable"),
                    "lamports": acc.get("lamports"),
                    "owner": acc.get("owner"),
                    "rent_epoch": acc.get("rentEpoch"),
                }
            })
        return jsonify({
            "program_id": program_id,
            "total_accounts": total,
            "limit": limit,
            "offset": offset,
            "accounts": fmt_accounts,
        })
    except RPCException as e:
        return error_response(e, status=404)
    except Exception as e:
        return error_response(e)

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)
